const binary = $input.item.binary || {};

const pdfKey = Object.keys(binary).find(key => {
  const file = binary[key];
  return file.mimeType === 'application/pdf' || file.fileExtension === 'pdf';
});

if (!pdfKey) {
  throw new Error('No PDF attachment found in this email.');
}

return {
  json: {
    ...$json,
    pdf_binary_key: pdfKey,
    original_file_name: binary[pdfKey].fileName || pdfKey,
    pdf_mime_type: binary[pdfKey].mimeType || '',
  },
  binary: {
    data: binary[pdfKey],
  },
};

const ai = $json.output || $json;

const now = new Date();

function formatDate(date) {
  return date.toISOString().split('T')[0];
}

function formatTime(date) {
  return date.toTimeString().split(' ')[0];
}

const receivedDate = formatDate(now);
const receivedTime = formatTime(now);

const dueDate = new Date(now);
dueDate.setDate(dueDate.getDate() + 7);

const safeDocType = (ai.document_type || "Other").replace(/\s+/g, "_");
const safeProjectCode = ai.project_code || "UNKNOWN";
const safeDocNo = ai.document_number || "NO-DOC-NO";
const safeRevision = ai.revision || "NA";

const newFileName = ai.new_file_name || `${safeProjectCode}_${safeDocType}_${safeDocNo}_Rev${safeRevision}.pdf`;

return {
  json: {
    log_id: `LOG-${Date.now()}`,
    date_received: receivedDate,
    time_received: receivedTime,

    project_name: ai.project_name || "",
    project_code: ai.project_code || "",
    document_type: ai.document_type || "",
    discipline: ai.discipline || "",
    document_number: ai.document_number || "",
    document_title: ai.document_title || "",
    revision: ai.revision || "",

    submitted_by: ai.submitted_by || "",
    sender_company: ai.sender_company || "",
    submission_date: ai.submission_date || "",
    status: ai.status || "Received",
    priority: ai.priority || "Normal",

    missing_fields: ai.missing_fields || "",
    duplicate_key: ai.duplicate_key || "",
    original_file_name: $json.original_file_name || "",
    new_file_name: newFileName,

    ai_remarks: ai.ai_remarks || "",
    action_required: ai.action_required || "Manual review required",

    review_due_date: formatDate(dueDate),
    days_pending: 0,
    duplicate_check: "Pending",
    latest_revision: "Yes",
    created_by: "AI Document Controller Assistant"
  },
  binary: $binary
};

const upload = $json;
const normalized = $("Check Duplicate and Revision").item.json;

const fileId = upload.id;
const driveLink = upload.webViewLink || `https://drive.google.com/file/d/${fileId}/view`;

const originalFileName =
  normalized.original_file_name ||
  $("Prepare PDF Binary").item.json.original_file_name ||
  "";

return {
  json: {
    ...normalized,
