    google_drive_file_id: fileId,
    google_drive_link: driveLink,
    uploaded_file_name: upload.name || normalized.new_file_name
  }
};

const pdfItem = $items("Prepare PDF Binary")[0];

if (!pdfItem.binary || !pdfItem.binary.data) {
  throw new Error("PDF binary data not found from Prepare PDF Binary node.");
}

return {
  json: {
    ...$json
  },
  binary: {
    data: pdfItem.binary.data
  }
};

const current = $items("Normalize AI Output")[0].json;
const existingRows = $input.all().map(item => item.json);

function normalize(value) {
  return String(value ?? "").trim().toLowerCase();
}

function pick(row, possibleNames) {
  // Exact match first
  for (const name of possibleNames) {
    if (row[name] !== undefined && row[name] !== null) {
      return row[name];
    }
  }

  // Flexible match: handles spaces, underscores, case differences
  const keys = Object.keys(row);
  for (const key of keys) {
    const cleanKey = key.toLowerCase().replace(/[\s_]/g, "");
    for (const name of possibleNames) {
      const cleanName = name.toLowerCase().replace(/[\s_]/g, "");
      if (cleanKey === cleanName) {
        return row[key];
      }
    }
  }

  return "";
}

function parseRevision(rev) {
  const value = String(rev ?? "").trim().toUpperCase();

  if (value === "") return -1;

  const numberMatch = value.match(/\d+/);
  if (numberMatch) return parseInt(numberMatch[0], 10);

  if (/^[A-Z]$/.test(value)) {
    return value.charCodeAt(0) - 64;
  }

  return 0;
}

const currentDocNo = normalize(current.document_number);
const currentRev = normalize(current.revision);
const currentRevNum = parseRevision(current.revision);

const validRows = existingRows.filter(row => {
  const rowDocNo = normalize(pick(row, [
    "Document_Number",
    "Document Number",
    "document_number"
  ]));

  return rowDocNo !== "";
});

const sameDocumentRows = validRows.filter(row => {
  const rowDocNo = normalize(pick(row, [
    "Document_Number",
    "Document Number",
    "document_number"
  ]));

  return rowDocNo === currentDocNo;
});

const exactDuplicate = sameDocumentRows.find(row => {
  const rowRev = normalize(pick(row, [
    "Revision",
    "revision",
    "Rev"
  ]));

  return rowRev === currentRev;
});

let highestExistingRevNum = -1;
let highestExistingRevision = "";

for (const row of sameDocumentRows) {
  const rowRevision = pick(row, [
    "Revision",
    "revision",
    "Rev"
  ]);

  const revNum = parseRevision(rowRevision);

  if (revNum > highestExistingRevNum) {
    highestExistingRevNum = revNum;
    highestExistingRevision = rowRevision;
  }
}

let duplicate_check = "New Document";
let latest_revision = "Yes";
let revision_status = "New";
let action_required = current.action_required || "Save to register";
let ai_remarks = current.ai_remarks || "";

if (exactDuplicate) {
  duplicate_check = "Duplicate";
  latest_revision = "No";
  revision_status = "Duplicate Same Revision";
  action_required = "Duplicate document found";
  ai_remarks = `Duplicate found: document number ${current.document_number} revision ${current.revision} already exists in register.`;
} else if (sameDocumentRows.length > 0 && currentRevNum > highestExistingRevNum) {
  duplicate_check = "New Revision";
  latest_revision = "Yes";
  revision_status = `New revision received. Previous latest revision was ${highestExistingRevision}.`;
  action_required = "Save new revision";
  ai_remarks = `New revision received for ${current.document_number}. Previous latest revision was ${highestExistingRevision}.`;
} else if (sameDocumentRows.length > 0 && currentRevNum < highestExistingRevNum) {
  duplicate_check = "Old Revision";
  latest_revision = "No";
  revision_status = `Older revision received. Latest existing revision is ${highestExistingRevision}.`;
  action_required = "Manual review required";
  ai_remarks = `Older revision received for ${current.document_number}. Latest existing revision is ${highestExistingRevision}.`;
}

return [{
  json: {
    ...current,

    duplicate_check,
    latest_revision,
    revision_status,
    action_required,
    ai_remarks,

    exact_duplicate_found: exactDuplicate ? "Yes" : "No",
    existing_rows_checked: existingRows.length,
    valid_document_rows_checked: validRows.length,
    same_document_rows_found: sameDocumentRows.length,
    previous_latest_revision: highestExistingRevision,

    debug_current_document_number: current.document_number,
    debug_current_revision: current.revision
  }
}];

